function DrawCirclePacking() {
  const { CirclePacking } = components;
  const dimensionField = "dimension_column";
  const measureField = "measure_column";
  const chartData = {
    name: "root",
    children: data.map((item) => ({
      name: String(item[dimensionField]),
      value: Number(item[measureField]) || 0
    }))
  };
  const config = {
    data: chartData,
    colorField: "name",
    label: { field: "name" },
    interactions: [{ type: "element-active" }]
  };
  return <div><CirclePacking {...config} /></div>;
}
